import { createApp, watch } from 'vue'
import pinia from '@/store/index'
import ElementPlus from 'element-plus'
import 'element-plus/dist/index.css'
import '@/utils/rem'
import { globalRegister } from '@/global'
import { useVersionStore } from '@/store/modules/version'
import { useWslStore } from '@/store/modules/ws'
import App from '@/App.vue'

const app = createApp(App)
app.use(pinia)
app.use(ElementPlus)
app.use(globalRegister)

const useWslStorePinia = useWslStore(pinia)
const versionStore = useVersionStore(pinia)

/* 监听版本设置，动态添加路由 */
watch(
  () => useWslStorePinia.versionSet,
  async (isSet) => {
    if (isSet) {
      try {
        const router = (
          await import(`@/router/index-${versionStore.currentVersion}.js`)
        ).default
        app.use(router)
        // 确保路由设置完成后再启用显示
        versionStore.setRouterEnabled(true)
      } catch (error) {
        console.error('路由加载失败:', error)
        alert('路由加载失败')
      }
    }
  }
)

app.mount('#app')
