import { defineStore } from 'pinia'
import proto from '@/utils/sdkapi_pb.js'
import throttle from 'lodash/throttle'
import { useVersionStore } from '@/store/modules/version'

export const useWslStore = defineStore({
  id: 'ws',
  state: () => ({
    error: null,
    received: null,
    sendData: null,
    isConnected: false,
    wifiCommandResult: null,
    versionSet: false
  }),
  actions: {
    websocketError(val) {
      this.error = val
    },

    // 节流函数，用于限制 CMD_UPDATE_STATUS_DATA 的输出频率
    throttledLog: throttle(function (commandName, j) {
      console.log(`${commandName}:`, j)
    }, 10000),

    websocketDataReceived(val) {
      this.received = val

      //调试robottype页面加载问题用
      // console.warn('[ws debug] 接收到的完整消息对象:', val)

      // if (!val?.statusData) {
      //   console.error('[ws debug] 接收到的数据中没有 statusData')
      // } else if (
      //   !val.statusData.robotDataList ||
      //   val.statusData.robotDataList.length === 0
      // ) {
      //   console.error('[ws debug] statusData 中 robotDataList 为空')
      // } else if (!val.statusData.robotDataList[0].robotType) {
      //   console.error('[ws debug] robotDataList[0] 中没有 robotType 字段')
      // } else {
      //   console.info(
      //     '[ws debug] robotType 获取成功：',
      //     val.statusData.robotDataList[0].robotType
      //   )
      // }

      // 初始根据robotType设置版本（兼容13和61）
      if (!this.versionSet && val?.statusData?.robotDataList?.[0]?.robotType) {
        const versionStore = useVersionStore()
        versionStore.setRobotType(val.statusData.robotDataList[0].robotType)
        this.versionSet = true
      }

      // 处理 WIFI 连接命令的结果
      if (val.command === proto.Command.CMD_CONNECT_WIFI) {
        this.wifiCommandResult = {
          command: val.command,
          success: val.errorCode === proto.ErrorCode.ERROR_CODE_SUCCESS,
          message: val.errorMessage
        }
      }

      // 获取命令名称
      const commandName = Object.keys(proto.Command).find(
        (key) => proto.Command[key] === val.command
      )

      // 控制 CMD_UPDATE_STATUS_DATA 的输出频率
      if (val.command === proto.Command.CMD_UPDATE_STATUS_DATA) {
        this.throttledLog(commandName, val)
      } else {
        console.log(`${commandName}:`, val)
      }
    },

    websocketSendData(val) {
      this.sendData = val
    },

    blobToArrayBuffer(blob) {
      const reader = new FileReader()

      reader.onload = () => {
        try {
          const d = proto.Response.deserializeBinary(reader.result)
          const j = proto.Response.toObject(null, d)
          this.websocketDataReceived(j)
        } catch (error) {
          this.websocketError({ error: 'Data processing failed' })
        }
      }

      reader.onerror = () => {
        this.websocketError({ error: 'Blob reading failed' })
      }

      reader.readAsArrayBuffer(blob)
    },

    setConnected(status) {
      this.isConnected = status
    }
  }
})
