<template>
  <!-- 等待加载 -->
  <template v-if="!useWslStorePinia.versionSet">
    <div class="loading-container">
      <el-icon class="loading-icon" :size="30">
        <Loading />
      </el-icon>
      <div>加载中...</div>
    </div>
  </template>

  <!-- 主要内容 -->
  <template v-else-if="versionStore.routerEnabled">
    <el-container style="width: 100vw; height: 100vh">
      <el-aside class="app-aside">
        <component :is="AsideComp" />
      </el-aside>
      <el-container>
        <el-header class="app-header flex">
          <div class="app-desc flex">
            <div
              :class="[
                'status-indicator',
                { connected: isConnected, disconnected: !isConnected }
              ]"
            ></div>
            <span>数据通信</span>
          </div>
        </el-header>
        <el-main class="app-main">
          <RouterView />
        </el-main>
      </el-container>
    </el-container>
  </template>
</template>

<script setup>
import { ref, onMounted, watch, computed } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useVersionStore } from '@/store/modules/version'
import { defineAsyncComponent } from 'vue'
import proto from '@/utils/sdkapi_pb.js'

import { RouterView } from 'vue-router'
import { Loading } from '@element-plus/icons-vue'

const versionStore = useVersionStore()
const useWslStorePinia = useWslStore()
const { sendData } = storeToRefs(useWslStorePinia)

// WebSocket相关
const socket = ref(null)
// 开发环境使用配置的URL，生产环境使用动态URL
const wsUrl =
  process.env.NODE_ENV === 'development'
    ? process.env.VUE_APP_WS_URL
    : `ws://${window.location.hostname}:7123/status`
const isConnected = ref(false) // 默认false，根据实际连接状态改变

// WebSocket重连机制
const maxRetries = 3
const retryDelay = 3000 // 3秒后重试
let retryCount = 0

/* 选项1. 显示机器人版本获取失败的警告，用这个 */
const startVersionTimeout = () => {
  setTimeout(() => {
    if (!useWslStorePinia.versionSet) {
      window.alert('页面加载失败')
    }
  }, 3000)
}

/* 选项2. 默认加载一个版本，只是用于无websocket链接情况下test，记得注释掉 */
// const startVersionTimeout = () => {
//   setTimeout(() => {
//     if (!useWslStorePinia.versionSet) {
//       // versionStore.setRobotType('tianyi-lite')
//       // versionStore.setRobotType('tianyi-proD')
//       // versionStore.setRobotType('tiangong-lite')
//       // versionStore.setRobotType('TG2.0-Lite')
//       // versionStore.setRobotType('TG2.0-Plus')
//       versionStore.setRobotType('TG2.0-Pro')
//       // versionStore.setRobotType('TY2.0-ProD')

//       useWslStorePinia.versionSet = true // 标记版本已设置
//     }
//   }, 500)
// }

// 动态引入侧边栏组件
const AsideComp = computed(() => {
  if (useWslStorePinia.versionSet) {
    return defineAsyncComponent(() =>
      import(`@/components/aside/index-${versionStore.currentVersion}.vue`)
    )
  }
  return null
})

const init = () => {
  if (typeof WebSocket === 'undefined') {
    alert('web socket unsupported!')
    return
  }

  connect()
  startVersionTimeout() // 启动超时检查
}

const connect = () => {
  try {
    socket.value = new WebSocket(wsUrl, 'status')
    socket.value.onopen = open
    socket.value.onerror = error
    socket.value.onmessage = getMessage
    socket.value.onclose = close
  } catch (err) {
    console.error('WebSocket connection error:', err)
    handleReconnect()
  }
}

const open = () => {
  console.log('socket connect success')
  isConnected.value = true
  useWslStorePinia.setConnected(true) // 更新 store 中的状态
  retryCount = 0 // 重置重试计数
  // getDataList() // 连接成功后获取数据列表

  // 连接成功后立即发送命令13
  const request = new proto.Request()
  request.setCommand(proto.Command.CMD_GET_STATUS_DATA)
  const data = request.serializeBinary()
  useWslStorePinia.websocketSendData({ data })
}

const error = () => {
  console.log('socket connect error')
  isConnected.value = false
  useWslStorePinia.setConnected(false) // 更新 store 中的状态
  handleReconnect()
}

const getMessage = (msg) => {
  useWslStorePinia.blobToArrayBuffer(msg.data)
}

const send = (data) => {
  if (!socket.value || socket.value.readyState !== WebSocket.OPEN) {
    console.error(
      'websocket send error: ready state: ' +
        (socket.value ? socket.value.readyState : 'socket not initialized')
    )
    useWslStorePinia.websocketError({
      readyState: socket.value ? socket.value.readyState : -1
    })
    return false
  }

  try {
    socket.value.send(data.data)
    return true
  } catch (err) {
    console.error('Send error:', err)
    return false
  }
}

const close = (event) => {
  console.log('socket closed with code:', event.code)
  isConnected.value = false
  useWslStorePinia.setConnected(false) // 更新 store 中的状态
  handleReconnect()
}

const handleReconnect = () => {
  if (retryCount < maxRetries) {
    retryCount++
    console.log(`Attempting to reconnect... (${retryCount}/${maxRetries})`)
    setTimeout(() => connect(), retryDelay)
  } else {
    console.log('Max retry attempts reached')
  }
}

// const getDataList = () => {
//   const request = new proto.Request()
//   request.setCommand(proto.Command.CMD_GET_DATA_LIST)
//   const data = request.serializeBinary()
//   console.log('get data list start……', request)
//   send({ data })
// }

// 生命周期
onMounted(() => {
  init()
})

// 监听store中的发送数据变化
watch(sendData, (newValue) => {
  if (newValue) {
    send(newValue)
  }
})
</script>

<style lang="less">
@import url('~@/assets/css/global.less');
</style>

<style lang="less" scoped>
.loading-container {
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  background: #f5f7fa;
  gap: 10px;

  .loading-icon {
    animation: rotating 4s linear infinite;
  }
}

.app-aside {
  width: 300px;
  border-right: 1px solid #eee;
  overflow-y: auto; // 允许内容垂直滚动
  // 隐藏滚动条但保留滚动功能
  &::-webkit-scrollbar {
    display: none;
  }
}
.app-header {
  height: 80px;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  .app-desc {
    display: flex;
    align-items: center;
    .status-indicator {
      width: 15px;
      height: 15px;
      border-radius: 50%;
      display: inline-block;
      vertical-align: middle;
      &.connected {
        background-color: #27ff23;
      }

      &.disconnected {
        background-color: #f92a2a;
      }
    }
    span {
      margin-left: 10px;
      line-height: 15px;
      vertical-align: middle;
    }
  }
}
.app-main {
  background: #eef6ff;
  padding: 20px;
  overflow-y: auto;
}
</style>
