import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useVersionStore = defineStore('version', () => {
  const robotType = ref('')
  const routerEnabled = ref(false)

  const VERSION_MAP = {
    //1.0
    'tiangong-lite': 'tg-l',
    'tianyi-lite': 'ty-l',
    'tianyi-proD': 'ty-pd',
    //2.0
    'TG2.0-Lite': 'tg-l-2',
    'TG2.0-Pro': 'tg-p-2',
    'TG2.0-Plus': 'tg-u-2',
    'TY2.0-ProD': 'ty-pd-2'
  }

  const currentVersion = computed(() => {
    return VERSION_MAP[robotType.value] || ''
  })

  const setRobotType = (type) => {
    robotType.value = type
  }

  const setRouterEnabled = (status) => {
    routerEnabled.value = status
  }

  return {
    currentVersion,
    routerEnabled,
    setRobotType,
    setRouterEnabled
  }
})
